package proxy

import (
	"bytes"
	"crypto/tls"
	"encoding/hex"
	"net"
	"testing"
	"time"
)

func TestGetServerNameFromClientHelloReadsFullFragmentedRecord(t *testing.T) {
	raw, err := hex.DecodeString("")
	if err != nil {
		t.Fatalf("decode clienthello: %v", err)
	}

	serverConn, clientConn := net.Pipe()
	defer serverConn.Close()
	defer clientConn.Close()

	go func() {
		_, _ = clientConn.Write(raw[:1280])
		time.Sleep(20 * time.Millisecond)
		_, _ = clientConn.Write(raw[1280:])
	}()

	serverName, rb := GetServerNameFromClientHello(serverConn)
	if serverName != "" {
		t.Fatalf("expected empty server name, got %q", serverName)
	}
	if !bytes.Equal(rb, raw) {
		t.Fatalf("expected full clienthello to be buffered, got %d bytes want %d", len(rb), len(raw))
	}
}

func TestGetServerNameFromClientHelloReturnsSNI(t *testing.T) {
	serverConn, clientConn := net.Pipe()
	defer serverConn.Close()

	done := make(chan struct{})
	go func() {
		defer close(done)
		defer clientConn.Close()
		tlsConn := tls.Client(clientConn, &tls.Config{
			ServerName:         "example.com",
			InsecureSkipVerify: true,
		})
		_ = tlsConn.SetDeadline(time.Now().Add(2 * time.Second))
		_ = tlsConn.Handshake()
	}()

	serverName, rb := GetServerNameFromClientHello(serverConn)
	if serverName != "example.com" {
		t.Fatalf("expected server name example.com, got %q", serverName)
	}
	if len(rb) == 0 {
		t.Fatal("expected clienthello bytes to be returned")
	}

	_ = serverConn.Close()
	<-done
}
